@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_6eacbc9d349946f0b4c1a775af520cb6.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    [Parameter, EditorRequired]
    public required IReadOnlyList<TItem> Items { get; set; }

    [Parameter, EditorRequired]
    public required RenderFragment<TItem> ChildContent { get; set; }

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    /// <summary>
    /// Distance in pixels from the bottom of the scroll container at which
    /// loading is triggered. Maps to the IntersectionObserver rootMargin.
    /// </summary>
    [Parameter]
    public int LoadThreshold { get; set; } = 200;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;
    private bool observerAttached;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-6eacbc9d349946f0b4c1a775af520cb6/js/infinite-scroll.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && !observerAttached && module is not null)
        {
            await module.InvokeVoidAsync("observe", sentinelRef, dotNetRef, LoadThreshold);
            observerAttached = true;
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;

        // If the parent signalled no more items, disconnect the observer.
        if (!HasMore)
        {
            await DisconnectObserverAsync();
        }

        StateHasChanged();
    }

    private async Task DisconnectObserverAsync()
    {
        if (module is not null && observerAttached)
        {
            await module.InvokeVoidAsync("disconnect");
            observerAttached = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await DisconnectObserverAsync();
            dotNetRef?.Dispose();

            if (module is not null)
            {
                await module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException)
        {
            // Circuit may already be gone during server-side disposal.
        }
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
    min-height: 1px; /* ensure IntersectionObserver can detect it */
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

